  '[{"title":"Join the Waitlist","description":"Get early access to the product.","href":"/waitlist"},{"title":"Read the Blog","description":"Learn more about what we are building.","href":"/blog"}]',
  NULL, '{"endDate":"2026-12-31T00:00:00Z","prizeTitle":"Premium Lifetime Access","prizeDescription":"Win a lifetime premium subscription.","bonusEntries":{"share":3,"follow":2,"referral":5}}', 'default', 1, 2, datetime('now')),

