INSERT OR REPLACE INTO pages (slug, parent_slug, title, description, content, faqs, related_pages, cover_image, metadata, layout, published, sort_order, updated_at) VALUES
('guides', NULL, 'Guides', 'In-depth guides to help you get the most out of our product and grow your business.',
  '[{"type":"paragraph","text":"Welcome to our guides hub. Whether you are just getting started or looking to master advanced features, we have a guide for you. Browse the topics below and dive into the one that fits your needs."}]',
  '[{"question":"Who are these guides for?","answer":"Our guides are written for founders, marketers, and product teams who want practical, actionable advice they can apply immediately."},{"question":"How often do you publish new guides?","answer":"We add new guides regularly based on user feedback and emerging best practices. Subscribe to the waitlist to get notified when new content drops."},{"question":"Can I request a guide on a specific topic?","answer":"Absolutely. Use our contact form to suggest a topic and we will prioritize it based on demand."}]',
  '[{"title":"About Us","description":"Learn more about our team and mission.","href":"/about"},{"title":"Resources","description":"Tools and downloads to support your workflow.","href":"/resources"}]',
  NULL, NULL, 'pillar', 1, 10, datetime('now')),

('guides/getting-started', 'guides', 'Getting Started Guide', 'Everything you need to know to set up your account and launch your first project.',
  '[{"type":"heading","text":"Getting Started in Three Steps","level":2},{"type":"paragraph","text":"Setting up your account takes less than five minutes. Begin by creating your workspace, inviting your team, and configuring your first project. This guide walks you through each step with screenshots and tips so you can hit the ground running."},{"type":"list","items":["Create your workspace and choose a plan","Invite team members and assign roles","Configure your first project and set milestones"],"ordered":true}]',
  '[{"question":"How long does setup take?","answer":"Most users complete the full setup in under five minutes. If you have a large team, allow an extra few minutes for invitations and role assignments."},{"question":"Can I change my plan later?","answer":"Yes. You can upgrade or downgrade your plan at any time from the billing settings page."}]',
  '[{"title":"Email Marketing Guide","description":"Learn to build effective email campaigns.","href":"/guides/email-marketing"},{"title":"SEO Basics Guide","description":"Improve your search engine rankings.","href":"/guides/seo-basics"}]',
  NULL, NULL, 'default', 1, 11, datetime('now')),

('guides/email-marketing', 'guides', 'Email Marketing Guide', 'Learn how to build, segment, and optimize email campaigns that convert.',
  '[{"type":"heading","text":"Email Marketing That Actually Works","level":2},{"type":"paragraph","text":"Email remains the highest-ROI channel for most businesses, but only when done right. This guide covers list building, segmentation, subject line optimization, and deliverability best practices so your messages land in the inbox and drive action."},{"type":"callout","text":"Companies that segment their email lists see up to 760% more revenue from email campaigns compared to one-size-fits-all blasts.","variant":"info"}]',
  '[{"question":"What is a good open rate?","answer":"Industry averages hover around 20-25%, but well-segmented lists targeting engaged subscribers often exceed 35%."},{"question":"How often should I email my list?","answer":"Start with once a week. Monitor unsubscribe rates and engagement metrics, then adjust frequency based on what your audience responds to."}]',
  '[{"title":"Getting Started Guide","description":"Set up your account and launch your first project.","href":"/guides/getting-started"},{"title":"SEO Basics Guide","description":"Improve your search engine rankings.","href":"/guides/seo-basics"}]',
  NULL, NULL, 'default', 1, 12, datetime('now')),

('guides/seo-basics', 'guides', 'SEO Basics Guide', 'A practical introduction to search engine optimization for founders and marketers.',
  '[{"type":"heading","text":"SEO Fundamentals You Can Apply Today","level":2},{"type":"paragraph","text":"Search engine optimization does not have to be complicated. This guide distills the most impactful practices into a clear framework: technical foundations, on-page optimization, and content strategy. Follow these steps to earn sustainable organic traffic without resorting to shortcuts."},{"type":"list","items":["Ensure your site loads in under 3 seconds on mobile","Write unique title tags and meta descriptions for every page","Build internal links between related content to help search engines understand your site structure"],"ordered":false}]',
  '[{"question":"How long does SEO take to show results?","answer":"Most sites begin seeing measurable improvements within three to six months of consistent effort. Competitive keywords may take longer."},{"question":"Do I need to hire an SEO agency?","answer":"Not necessarily. Many founders see strong results by applying the fundamentals in this guide themselves. An agency can help if you need to scale quickly or compete in a crowded market."}]',
  '[{"title":"Getting Started Guide","description":"Set up your account and launch your first project.","href":"/guides/getting-started"},{"title":"Email Marketing Guide","description":"Learn to build effective email campaigns.","href":"/guides/email-marketing"}]',
  NULL, NULL, 'default', 1, 13, datetime('now')),

('about', NULL, 'About Us', 'Meet the team behind the product and learn what drives us.',
  '[{"type":"heading","text":"Our Story","level":2},{"type":"paragraph","text":"We started this company because we experienced the problem firsthand. After years of cobbling together spreadsheets, half-baked tools, and duct-tape integrations, we decided to build the solution we wished had existed. Our small, distributed team brings experience from companies like Stripe, Vercel, and Shopify."},{"type":"callout","text":"Our mission is to give every founder and small team the same operational advantage that well-funded startups take for granted.","variant":"tip"},{"type":"paragraph","text":"We are based nowhere and everywhere — a fully remote team spanning four time zones. We believe great products are built by people who care deeply about the problem, not by people who happen to sit in the same office."}]',
  '[{"question":"Where is your company based?","answer":"We are a fully remote company with team members across North America and Europe. Our legal entity is incorporated in Delaware."},{"question":"Are you hiring?","answer":"We are always interested in hearing from talented people. Check our careers page or reach out via the contact form."},{"question":"How is the company funded?","answer":"We are bootstrapped and profitable. This means we answer to our customers, not investors."}]',
  '[{"title":"Guides","description":"In-depth guides on product and growth topics.","href":"/guides"},{"title":"Contact","description":"Get in touch with our team.","href":"/contact"}]',
  NULL, NULL, 'landing', 1, 14, datetime('now')),

('resources', NULL, 'Resources', 'Downloadable tools, templates, and reference materials to accelerate your workflow.',
  '[{"type":"paragraph","text":"We have compiled our most useful tools and templates into one place. Whether you need a project planning spreadsheet, an email campaign checklist, or a pitch deck framework, you will find it here. All resources are free to use and regularly updated."}]',
  '[{"question":"Are these resources free?","answer":"Yes, every resource on this page is free to download and use. No signup required."},{"question":"Can I share these with my team?","answer":"Absolutely. All resources are licensed for internal business use. Share them with anyone on your team."}]',
  '[{"title":"Guides","description":"Step-by-step guides for common workflows.","href":"/guides"},{"title":"About Us","description":"Learn more about our team and mission.","href":"/about"}]',
  NULL, NULL, 'listing', 1, 15, datetime('now'));

